def diffcount(a,b):
    diff_added=[]
    diff_removed=[]
    h=len(a)
    w=len(a[0])
    for r in range(h):
        for c in range(w):
            if a[r][c]!=b[r][c]:
                if a[r][c]==0 and b[r][c]!=0:
                    diff_added.append((r,c))
                elif a[r][c]!=0 and b[r][c]==0:
                    diff_removed.append((r,c))
                else:
                    diff_removed.append((r,c))
                    diff_added.append((r,c))
    return diff_added,diff_removed
