def transform(grid):
    h=len(grid); w=len(grid[0])
    # find counts per color
    from collections import Counter
    cnt=Counter()
    for row in grid:
        for v in row:
            if v!=0:
                cnt[v]+=1
    if not cnt:
        return grid
    primary=max(cnt.items(), key=lambda x:x[1])[0]
    # produce copy keep only primary
    new=[[primary if v==primary else 0 for v in row] for row in grid]
    changed=True
    while changed:
        changed=False
        for r in range(h):
            for c in range(w):
                if new[r][c]==0:
                    # count orth neighbors with primary
                    neigh=0
                    for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                        nr, nc = r+dr, c+dc
                        if 0<=nr<h and 0<=nc<w and new[nr][nc]==primary:
                            neigh+=1
                    if neigh>=2:
                        new[r][c]=primary
                        changed=True
    return new
