def transform3(grid):
    h=len(grid); w=len(grid[0])
    from collections import Counter
    cnt=Counter()
    for row in grid:
        for v in row:
            if v!=0:
                cnt[v]+=1
    primary=max(cnt.items(), key=lambda x:x[1])[0]
    new=[[primary if v==primary else 0 for v in row] for row in grid]
    def has_neighbors(r,c):
        for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr=r+dr; nc=c+dc
            if 0<=nr<h and 0<=nc<w and new[nr][nc]==primary:
                return True
        return False
    # remove isolated
    for r in range(h):
        for c in range(w):
            if new[r][c]==primary and not has_neighbors(r,c):
                new[r][c]=0
    # fill
    changed=True
    while changed:
        changed=False
        add=[]
        for r in range(h):
            for c in range(w):
                if new[r][c]==0:
                    neigh=0
                    for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                        nr=r+dr; nc=c+dc
                        if 0<=nr<h and 0<=nc<w and new[nr][nc]==primary:
                            neigh+=1
                    if neigh>=2:
                        add.append((r,c))
        if add:
            changed=True
            for r,c in add:
                new[r][c]=primary
    return new
