def transform4(grid):
    h=len(grid); w=len(grid[0])
    from collections import Counter
    cnt=Counter()
    for row in grid:
        for v in row:
            if v!=0:
                cnt[v]+=1
    if not cnt:
        return [row[:] for row in grid]
    primary=max(cnt.items(), key=lambda x:x[1])[0]
    new=[[v for v in row] for row in grid]
    # First pass: remove non-primary colors if they will not be converted
    for r in range(h):
        for c in range(w):
            v=grid[r][c]
            if v==0:
                new[r][c]=0
                continue
            if v==primary:
                continue
            # non-primary color
            neigh=0
            for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                nr=r+dr; nc=c+dc
                if 0<=nr<h and 0<=nc<w and grid[nr][nc]==primary:
                    neigh+=1
            if neigh>=2:
                new[r][c]=primary
            else:
                new[r][c]=0
    # second pass: set any remaining non-primary to 0
    for r in range(h):
        for c in range(w):
            if new[r][c]!=primary:
                new[r][c]=0
    # remove isolated primary
    for r in range(h):
        for c in range(w):
            if new[r][c]==primary:
                neigh=0
                for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr=r+dr; nc=c+dc
                    if 0<=nr<h and 0<=nc<w and new[nr][nc]==primary:
                        neigh+=1
                if neigh==0:
                    new[r][c]=0
    return new
